+  box-shadow: 0 34px 88px rgba(0, 0, 0, 0.6), inset 0 2px 4px rgba(255, 255, 255, 0.12);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  z-index: 10;
+  position: absolute;
+}
+
+.insightCore {
+  width: 80px;
+  height: 80px;
+  border-radius: 50%;
+  background: radial-gradient(circle at 30% 30%, var(--metal-light) 0%, var(--metal-mid) 60%, var(--metal-dark) 100%);
+  box-shadow:
+    -4px -4px 12px rgba(255, 255, 255, 0.04),
+    10px 10px 28px rgba(0, 0, 0, 0.45),
+    inset -2px -2px 6px rgba(0, 0, 0, 0.25),
+    inset 2px 2px 6px rgba(255, 255, 255, 0.88);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  position: relative;
+}
+
+.insightCore::before {
+  content: '';
+  position: absolute;
+  inset: -12px;
+  border-radius: 50%;
+  border: 1px solid rgba(255, 255, 255, 0.12);
+  animation: pulse 4s cubic-bezier(0.4, 0, 0.6, 1) infinite;
+}
+
+@keyframes pulse {
+  0% {
+    transform: scale(1);
+    opacity: 1;
+  }
+  100% {
+    transform: scale(1.5);
+    opacity: 0;
+  }
+}
+
+.insightCore svg {
+  width: 32px;
+  height: 32px;
+  stroke: #0b0b0c;
+  stroke-width: 1.5;
+  fill: none;
+  filter: drop-shadow(0px 1px 0px rgba(255, 255, 255, 0.55));
+}
+
+.metaLabel {
+  position: absolute;
+  font-size: 10px;
+  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;
+  color: rgba(255, 255, 255, 0.45);
+  letter-spacing: 0.12em;
+  pointer-events: none;
+}
+
+.lbl1 {
+  bottom: -24px;
+  left: 50%;
+  transform: translateX(-50%);
+}
+
+.lbl2 {
+  top: -24px;
+  right: -20px;
+}
+
+@media (max-width: 1024px) {
+  .main {
+    grid-template-columns: 1fr;
+    padding: 100px 40px;
+    gap: 60px;
+  }
+
+  .canvasSection {
+    height: 500px;
+  }
+
+  .spatialScene {
+    transform: none;
+  }
+
+  .spatialBackdrop {
+    transform: none;
+  }
+}
